"""
Utility script to test the backend API without the frontend.
"""
import requests
from pathlib import Path

API_URL = "http://localhost:8000/predict"
IMAGE_PATH = "path/to/your/test_image.jpg"  # Change this to your test image


def test_prediction(image_path: str):
    """Test the prediction endpoint."""

    if not Path(image_path).exists():
        print(f"Error: Image not found at {image_path}")
        return

    try:
        with open(image_path, 'rb') as f:
            files = {'file': f}
            response = requests.post(API_URL, files=files)

        if response.status_code == 200:
            result = response.json()
            print("Prediction Result:")
            print(f"  Class: {result['predicted_class']}")
            print(f"  Confidence: {result['confidence_score']:.2%}")
        else:
            print(f"Error: {response.status_code}")
            print(response.json())

    except requests.exceptions.ConnectionError:
        print("Error: Could not connect to API. Is the backend running?")
    except Exception as e:
        print(f"Error: {str(e)}")


if __name__ == "__main__":
    import sys

    if len(sys.argv) > 1:
        IMAGE_PATH = sys.argv[1]

    test_prediction(IMAGE_PATH)

const API_URL = 'http://localhost:8000/predict';

const classExplanations = {
    'Normal': 'The image appears to show a healthy eye with no visible signs of infection or abnormalities.',
    'Conjunctivitis': 'The image shows possible signs of conjunctivitis (pink eye) including redness, swelling, or discharge. Consult an eye doctor for proper diagnosis and treatment.',
    'Cataract': 'The image may indicate cataract formation, characterized by cloudiness in the lens. This condition typically requires professional medical evaluation and treatment.',
    'Glaucoma': 'The image suggests potential signs of glaucoma, a serious eye condition that can damage the optic nerve. Immediate consultation with an ophthalmologist is recommended.'
};

const fileInput = document.getElementById('fileInput');
const uploadArea = document.getElementById('uploadArea');
const previewContainer = document.getElementById('previewContainer');
const previewImage = document.getElementById('previewImage');
const analyzeBtn = document.getElementById('analyzeBtn');
const removeBtn = document.getElementById('removeBtn');
const resultsSection = document.getElementById('resultsSection');
const errorSection = document.getElementById('errorSection');
const resultClass = document.getElementById('resultClass');
const confidenceScore = document.getElementById('confidenceScore');
const resultExplanation = document.getElementById('resultExplanation');
const errorMessage = document.getElementById('errorMessage');
const retryBtn = document.getElementById('retryBtn');

let selectedFile = null;

uploadArea.addEventListener('click', () => {
    fileInput.click();
});

fileInput.addEventListener('change', handleFileSelect);

uploadArea.addEventListener('dragover', (e) => {
    e.preventDefault();
    uploadArea.classList.add('dragover');
});

uploadArea.addEventListener('dragleave', () => {
    uploadArea.classList.remove('dragover');
});

uploadArea.addEventListener('drop', (e) => {
    e.preventDefault();
    uploadArea.classList.remove('dragover');

    const files = e.dataTransfer.files;
    if (files.length > 0) {
        handleFile(files[0]);
    }
});

removeBtn.addEventListener('click', (e) => {
    e.stopPropagation();
    removeFile();
});

analyzeBtn.addEventListener('click', analyzeImage);

retryBtn.addEventListener('click', () => {
    errorSection.style.display = 'none';
});

function handleFileSelect(e) {
    const file = e.target.files[0];
    if (file) {
        handleFile(file);
    }
}

function handleFile(file) {
    if (!file.type.match('image.*')) {
        showError('Please select a valid image file (JPEG or PNG).');
        return;
    }

    selectedFile = file;

    const reader = new FileReader();
    reader.onload = (e) => {
        previewImage.src = e.target.result;
        uploadArea.style.display = 'none';
        previewContainer.style.display = 'block';
        analyzeBtn.disabled = false;
        resultsSection.style.display = 'none';
        errorSection.style.display = 'none';
    };
    reader.readAsDataURL(file);
}

function removeFile() {
    selectedFile = null;
    fileInput.value = '';
    previewImage.src = '';
    uploadArea.style.display = 'block';
    previewContainer.style.display = 'none';
    analyzeBtn.disabled = true;
    resultsSection.style.display = 'none';
    errorSection.style.display = 'none';
}

async function analyzeImage() {
    if (!selectedFile) {
        showError('Please select an image first.');
        return;
    }

    document.body.classList.add('loading');
    resultsSection.style.display = 'none';
    errorSection.style.display = 'none';

    try {
        const formData = new FormData();
        formData.append('file', selectedFile);

        const response = await fetch(API_URL, {
            method: 'POST',
            body: formData
        });

        if (!response.ok) {
            const errorData = await response.json();
            throw new Error(errorData.detail || 'Analysis failed. Please try again.');
        }

        const data = await response.json();

        displayResult(data);

    } catch (error) {
        showError(error.message || 'An error occurred during analysis. Please ensure the backend server is running.');
    } finally {
        document.body.classList.remove('loading');
    }
}

function displayResult(data) {
    resultClass.textContent = data.predicted_class;
    confidenceScore.textContent = (data.confidence_score * 100).toFixed(1) + '%';
    resultExplanation.textContent = classExplanations[data.predicted_class] || 'Analysis complete.';

    const resultsCard = document.querySelector('.results-card');

    if (data.predicted_class === 'Normal') {
        resultsCard.style.borderLeftColor = '#10b981';
        resultClass.style.color = '#10b981';
    } else if (data.predicted_class === 'Conjunctivitis') {
        resultsCard.style.borderLeftColor = '#f59e0b';
        resultClass.style.color = '#f59e0b';
    } else if (data.predicted_class === 'Cataract') {
        resultsCard.style.borderLeftColor = '#8b5cf6';
        resultClass.style.color = '#8b5cf6';
    } else if (data.predicted_class === 'Glaucoma') {
        resultsCard.style.borderLeftColor = '#ef4444';
        resultClass.style.color = '#ef4444';
    }

    resultsSection.style.display = 'block';

    resultsSection.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
}

function showError(message) {
    errorMessage.textContent = message;
    errorSection.style.display = 'block';

    errorSection.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
}

document.addEventListener('DOMContentLoaded', () => {
    console.log('Eye Infection Detection App initialized');
});

/* Reset and Base Styles */
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

:root {
    --primary-color: #2563eb;
    --primary-hover: #1d4ed8;
    --secondary-color: #64748b;
    --success-color: #10b981;
    --warning-color: #f59e0b;
    --danger-color: #ef4444;
    --background-color: #f8fafc;
    --card-background: #ffffff;
    --text-primary: #1e293b;
    --text-secondary: #64748b;
    --border-color: #e2e8f0;
    --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.05);
    --shadow-md: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
    --shadow-lg: 0 10px 15px -3px rgba(0, 0, 0, 0.1);
    --radius-md: 0.5rem;
    --radius-lg: 0.75rem;
}

body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, sans-serif;
    background-color: var(--background-color);
    color: var(--text-primary);
    line-height: 1.6;
    min-height: 100vh;
}

.container {
    max-width: 600px;
    margin: 0 auto;
    padding: 1rem;
    display: flex;
    flex-direction: column;
    min-height: 100vh;
}

/* Header */
.header {
    text-align: center;
    padding: 2rem 0;
}

.header h1 {
    font-size: 1.75rem;
    font-weight: 700;
    color: var(--primary-color);
    margin-bottom: 0.5rem;
}

.subtitle {
    font-size: 0.875rem;
    color: var(--text-secondary);
}

/* Main Content */
.main-content {
    flex: 1;
    display: flex;
    flex-direction: column;
    gap: 1.5rem;
}

/* Upload Section */
.upload-section {
    animation: fadeIn 0.5s ease-out;
}

.upload-card {
    background: var(--card-background);
    border-radius: var(--radius-lg);
    padding: 1.5rem;
    box-shadow: var(--shadow-md);
}

.upload-card h2 {
    font-size: 1.25rem;
    font-weight: 600;
    margin-bottom: 0.5rem;
    color: var(--text-primary);
}

.upload-hint {
    font-size: 0.875rem;
    color: var(--text-secondary);
    margin-bottom: 1rem;
}

/* Upload Area */
.upload-area {
    border: 2px dashed var(--border-color);
    border-radius: var(--radius-lg);
    padding: 2rem;
    text-align: center;
    cursor: pointer;
    transition: all 0.3s ease;
    background: #f9fafb;
}

.upload-area:hover,
.upload-area.dragover {
    border-color: var(--primary-color);
    background: #eff6ff;
}

.upload-icon {
    color: var(--primary-color);
    margin-bottom: 1rem;
}

.upload-text {
    font-weight: 500;
    color: var(--text-primary);
    margin-bottom: 0.25rem;
}

.upload-subtext {
    font-size: 0.75rem;
    color: var(--text-secondary);
}

/* Preview Container */
.preview-container {
    margin-top: 1.5rem;
    animation: fadeIn 0.3s ease-out;
}

.preview-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
}

.preview-header h3 {
    font-size: 1rem;
    font-weight: 600;
}

.btn-remove {
    background: transparent;
    border: 1px solid var(--danger-color);
    color: var(--danger-color);
    padding: 0.5rem 1rem;
    border-radius: var(--radius-md);
    font-size: 0.875rem;
    cursor: pointer;
    transition: all 0.2s ease;
}

.btn-remove:hover {
    background: var(--danger-color);
    color: white;
}

#previewImage {
    width: 100%;
    max-height: 300px;
    object-fit: contain;
    border-radius: var(--radius-md);
    border: 1px solid var(--border-color);
}

/* Buttons */
.btn-analyze {
    width: 100%;
    background: var(--primary-color);
    color: white;
    border: none;
    padding: 1rem;
    border-radius: var(--radius-md);
    font-size: 1rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.3s ease;
    margin-top: 1.5rem;
    position: relative;
}

.btn-analyze:hover:not(:disabled) {
    background: var(--primary-hover);
    transform: translateY(-1px);
    box-shadow: var(--shadow-lg);
}

.btn-analyze:active:not(:disabled) {
    transform: translateY(0);
}

.btn-analyze:disabled {
    background: var(--secondary-color);
    cursor: not-allowed;
    opacity: 0.6;
}

.btn-text {
    display: inline;
}

.btn-loading {
    display: none;
    align-items: center;
    justify-content: center;
    gap: 0.5rem;
}

.spinner {
    width: 20px;
    height: 20px;
    border: 2px solid rgba(255, 255, 255, 0.3);
    border-top-color: white;
    border-radius: 50%;
    animation: spin 0.8s linear infinite;
}

@keyframes spin {
    to { transform: rotate(360deg); }
}

/* Results Section */
.results-section {
    animation: slideUp 0.5s ease-out;
}

.results-card {
    background: var(--card-background);
    border-radius: var(--radius-lg);
    padding: 1.5rem;
    box-shadow: var(--shadow-md);
    border-left: 4px solid var(--success-color);
}

.results-card h2 {
    font-size: 1.25rem;
    font-weight: 600;
    margin-bottom: 1rem;
}

.result-content {
    text-align: center;
    padding: 1.5rem 0;
}

.result-class {
    font-size: 2rem;
    font-weight: 700;
    color: var(--text-primary);
    margin-bottom: 0.5rem;
}

.result-confidence {
    font-size: 1rem;
    color: var(--text-secondary);
}

#confidenceScore {
    font-weight: 600;
    color: var(--primary-color);
}

.result-explanation {
    margin-top: 1rem;
    padding-top: 1rem;
    border-top: 1px solid var(--border-color);
}

.result-explanation p {
    font-size: 0.875rem;
    color: var(--text-secondary);
    line-height: 1.5;
}

/* Error Section */
.error-section {
    animation: shake 0.5s ease-out;
}

.error-card {
    background: #fef2f2;
    border: 1px solid #fecaca;
    border-radius: var(--radius-lg);
    padding: 2rem;
    text-align: center;
}

.error-icon {
    color: var(--danger-color);
    margin-bottom: 1rem;
}

.error-card h3 {
    color: var(--danger-color);
    margin-bottom: 0.5rem;
}

.error-card p {
    color: var(--text-secondary);
    margin-bottom: 1rem;
    font-size: 0.875rem;
}

.btn-retry {
    background: var(--primary-color);
    color: white;
    border: none;
    padding: 0.75rem 1.5rem;
    border-radius: var(--radius-md);
    font-weight: 600;
    cursor: pointer;
    transition: all 0.2s ease;
}

.btn-retry:hover {
    background: var(--primary-hover);
}

/* Disclaimer */
.disclaimer {
    display: flex;
    align-items: flex-start;
    gap: 0.75rem;
    padding: 1rem;
    background: #fffbeb;
    border: 1px solid #fed7aa;
    border-radius: var(--radius-md);
    margin-top: 2rem;
}

.disclaimer-icon {
    color: var(--warning-color);
    flex-shrink: 0;
    margin-top: 0.125rem;
}

.disclaimer p {
    font-size: 0.75rem;
    color: #92400e;
    line-height: 1.4;
}

/* Animations */
@keyframes fadeIn {
    from {
        opacity: 0;
    }
    to {
        opacity: 1;
    }
}

@keyframes slideUp {
    from {
        opacity: 0;
        transform: translateY(20px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

@keyframes shake {
    0%, 100% {
        transform: translateX(0);
    }
    25% {
        transform: translateX(-10px);
    }
    75% {
        transform: translateX(10px);
    }
}

/* Responsive Design */
@media (max-width: 480px) {
    .container {
        padding: 0.75rem;
    }

    .header {
        padding: 1.5rem 0;
    }

    .header h1 {
        font-size: 1.5rem;
    }

    .upload-card {
        padding: 1.25rem;
    }

    .upload-area {
        padding: 1.5rem;
    }

    .result-class {
        font-size: 1.75rem;
    }
}

/* PWA and Mobile Optimizations */
@media (orientation: landscape) and (max-height: 500px) {
    .header {
        padding: 1rem 0;
    }

    .header h1 {
        font-size: 1.25rem;
    }

    .upload-area {
        padding: 1rem;
    }
}

/* Touch Targets for Mobile */
button,
.upload-area {
    -webkit-tap-highlight-color: transparent;
}

button:active {
    transform: scale(0.98);
}

/* Loading State */
body.loading .btn-analyze {
    pointer-events: none;
}

body.loading .btn-text {
    display: none;
}

body.loading .btn-loading {
    display: inline-flex;
}
